CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_app_member_refer() RETURNS trigger AS $BODY$
declare ls_mem_type sc_mem_m_application_form.mem_type%type;
BEGIN

  if coalesce(NEW.application_form_no::text, '') = '' then
    CALL spa_dberrcol('sc_mem_m_app_member_refer','application_form_no',NEW.application_form_no);
  end if;

  if pka.auto_seqno then
    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
      select max(seq_no) into STRICT NEW.seq_no
      from sc_mem_m_app_member_refer
      where (application_form_no = NEW.application_form_no);
      NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
    end if;
  end if;

  if coalesce(NEW.concern_code::text, '') = '' or NEW.concern_code = ' ' then
    NEW.concern_code := '00';
  end if;

  select mem_type into STRICT ls_mem_type
  from sc_mem_m_application_form
  where application_form_no = NEW.application_form_no;

  --Niorn 2023-02-23 TGE สมาชิกสมทบ ต้องระบุสมาชิกอ้างอิง
  if ls_mem_type = '02' and  coalesce(NEW.membership_no::text, '') = '' then
    CALL spa_dberrcol('สมาชิกสมทบ','กรุณาระบุสมาชิกอ้างอิง',NEW.membership_no);
  end if;
RETURN NEW;
end
